#nullable enable // autogenerated

using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.ghast_Move)]
    public class Ghast_MoveBehaviour : AIEntityBehaviour
    {
        public Ghast_MoveBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (entity.State == STATE_WALK || entity.State == STATE_RANGED_ATTACK)
            {
                entity.UpdateWalkVelocity();
            }
        }
        public const int STATE_WALK = LogicEnemyStates.WALK;
        public const int STATE_RANGED_ATTACK = LogicEnemyStates.RANGED_ATTACK;
    }
}
